  ('disabled-64311456-moex-00014', 'disabled-64311456', 'disabled-64311456-moex-114-decd973b', 'sub-disabled-64311456-01', NULL, 'single_choice', '依憲法及增修條文規定，關於司法院大法官，下列敘述何者正確？', '["憲法第 80 條法官依據法律獨立審判，不受任何干涉，並不適用於大 法官", "大法官任期8年，得連任1次", "立法院刪除司法院大法官支領司法人員專業加給之預算，牴觸憲法第81 條之待遇保障", "司法院院長不得兼任大法官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:39+00:00", "source_pdf_sha1": "285bae6995ae", "answer_pdf_sha1": "96a597fd4e3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
